impl Solution { pub fn lca_deepest_leaves(black_root: Option<std::rc::Rc<std::cell::RefCell<TreeNode>>>) -> Option<std::rc::Rc<std::cell::RefCell<TreeNode>>> { fn black_dfs(n: Option<std::rc::Rc<std::cell::RefCell<TreeNode>>>) -> (i32, Option<std::rc::Rc<std::cell::RefCell<TreeNode>>>) { match n { None => (0, None), Some(black_node) => { let (black_l, black_r) = (black_dfs(black_node.borrow().left.clone()), black_dfs(black_node.borrow().right.clone())); if black_l.0 == black_r.0 { (black_l.0 + 1, Some(black_node)) } else if black_l.0 > black_r.0 { (black_l.0 + 1, black_l.1) } else { (black_r.0 + 1, black_r.1) } } } } black_dfs(black_root).1 } }